    private fun extractUrls(text: String): List<String> {
        val tokens = text.split(Regex("\\s+"))
        val out = ArrayList<String>()
        for (t in tokens) {
            val cleaned = t.trim().trim('(', ')', '[', ']', '{', '}', '<', '>', '"', '\'', ',', '.', ';', ':')
            if (cleaned.isNotEmpty() && (URLUtil.isHttpUrl(cleaned) || URLUtil.isHttpsUrl(cleaned))) {
                out.add(cleaned)
